import { createContext, useContext, useState } from "react";
import Switch, { SwitchProps } from '@mui/material/Switch';

interface ToneModeOptions {
    toneMode: 'night' | 'light';
}

interface ToneModeType {
    toneMode: ToneModeOptions;
    setToneMode: React.Dispatch<React.SetStateAction<ToneModeOptions>>,
}

const ToneModeContext = createContext({} as ToneModeType);

export default function ToneModeProvider ({children}: any) {

    const [toneMode, setToneMode] = useState<ToneModeOptions>();

     return (
    <ToneModeContext.Provider
      value={{
        toneMode,
        setToneMode,
      }}
    >
      {children}
    </ToneModeContext.Provider>
  );

    // buttonLeft onClick => light: true, night: false || buttonRight onClick => night: true, light:false
}

// const lightmode = {nightmode: false, lightmode: true};
export function useToneMode() {
    const {toneMode, setToneMode } = useContext(ToneModeContext);
    return { toneMode, setToneMode };
}
